Select distinct 
    d.CID
    ,d.DepositID
    ,dt.DepositType
    ,d.Amount
    ,d.ModificationDate
    ,f.Name as FundingType
    ,p.Name as PaymentStatus
    ,r.Name as DepositRiskStatus
    ,ad.Response as TransactionResponse
    ,th.ThreeDsResponseTypesName
,d.FundingID
from 
    billing.bronze_etoro_billing_deposit d
LEFT JOIN 
    dwh.gold_sql_dp_prod_we_dwh_dbo_fact_billingdeposit bd on bd.DepositID = d.DepositID
LEFT JOIN 
    bi_db.gold_sql_dp_prod_we_bi_db_dbo_v_bi_db_alldeposits ad on ad.DepositID = d.DepositID
LEFT JOIN 
    dwh.gold_sql_dp_prod_we_dwh_dbo_dim_paymentstatus p on p.PaymentStatusID = d.PaymentStatusID
LEFT JOIN 
    general.bronze_etoro_dictionary_deposittype dt on dt.DepositTypeID = d.DepositTypeID
LEFT JOIN 
    dwh.gold_sql_dp_prod_we_dwh_dbo_dim_fundingtype f on f.FundingTypeID = bd.FundingTypeID
LEFT JOIN 
    dwh.gold_sql_dp_prod_we_dwh_dbo_dim_riskmanagementstatus r on r.RiskManagementStatusID = bd.RiskManagementStatusID
LEFT JOIN 
    dwh.gold_sql_dp_prod_we_dwh_dbo_dim_threedsresponsetypes th on th.ThreeDsResponseTypeID = bd.ThreeDsResponseType
